    #[Route('/nouveau', name: 'evenement_add', methods: ['GET','POST'])]

    public function new(Request $request, EntityManagerInterface $em): Response

    {

        $allowedRoles = ['ROLE_ADMIN', 'ROLE_MEDECIN', 'ROLE_RESPONSABLE_LABO', 'ROLE_RESPONSABLE_PARA', 'ROLE_PATIENT'];

        $hasPermission = false;

        

        foreach ($allowedRoles as $role) {

            if ($this->isGranted($role)) {

                $hasPermission = true;

                break;

            }

        }

        

        if (!$hasPermission) {

            throw new AccessDeniedException('Vous n\'avez pas acces a cet evenement.');

        }



        $user = $this->getUser();

        if (!$user) {

            return $this->redirectToRoute('app_login');

        }



        $evenement = new Evenement();

        

        if ($this->isGranted('ROLE_PATIENT')) {

            $evenement->setStatut('en_attente_approbation');

        } else {

            $evenement->setStatut('planifie');

        }



        $form = $this->createForm(EvenementType::class, $evenement, [

            'user_role' => ($user->getRoles()[0] ?? 'ROLE_USER'),

            'is_admin' => $this->isGranted('ROLE_ADMIN'),

            'series_candidates' => $this->buildSeriesCandidateChoices(),

        ]);

        

        $form->handleRequest($request);



        if ($form->isSubmitted() && $form->isValid()) {

            $errors = [];

            $evenement->setCreateur($user);

            $this->applySurfaceEditionSelection($form, $evenement);

            

            if (!$evenement->getDateDebut()) {

                $errors[] = 'La date de debut est obligatoire.';

            }

            

            if (!$evenement->getDateFin()) {

                $errors[] = 'La date de fin est obligatoire.';

            }

            

            if ($evenement->getDateDebut() && $evenement->getDateFin()) {

                if ($evenement->getDateFin() < $evenement->getDateDebut()) {

                    $errors[] = 'La date de fin doit etre posterieure a la date de debut.';

                }

                

                $now = new \DateTime();

                if ($evenement->getDateDebut() < $now) {

                    $errors[] = 'La date de debut ne peut pas etre dans le passe.';

                }

                

                $diff = $evenement->getDateDebut()->diff($evenement->getDateFin());

                if ($diff->days > 30) {

                    $errors[] = 'La duree de l\'evenement ne peut pas depasser 30 jours.';

                }

            }

            

            if ($evenement->getPlacesMax() !== null) {

                if ($evenement->getPlacesMax() <= 0) {

                    $errors[] = 'Le nombre de places doit etre superieur a zero.';

                }

                if ($evenement->getPlacesMax() > 10000) {

                    $errors[] = 'Le nombre de places ne peut pas depasser 10000.';

                }

            }

            

            if ($evenement->getTarif() !== null) {

                if ($evenement->getTarif() < 0) {

                    $errors[] = 'Le tarif ne peut pas etre negatif.';

                }

                if ($evenement->getTarif() > 10000) {

                    $errors[] = 'Le tarif ne peut pas depasser 10000 TND.';

                }

            }

            

            if (strlen($evenement->getTitre()) < 5) {

                $errors[] = 'Le titre doit contenir au moins 5 caracteres.';

            }

            

            if (strlen($evenement->getTitre()) > 200) {

                $errors[] = 'Le titre ne peut pas depasser 200 caracteres.';

            }

            

            if ($evenement->getDescription() && strlen($evenement->getDescription()) > 5000) {

                $errors[] = 'La description ne peut pas depasser 5000 caracteres.';

            }

            

            if ($evenement->getLieu() && strlen($evenement->getLieu()) > 500) {

                $errors[] = 'Le lieu ne peut pas depasser 500 caracteres.';

            }



            $this->appendSchedulingConflictErrors($evenement, $errors, null);

            $this->appendOperationalValidationErrors($evenement, $errors);

            

            if (!empty($errors)) {

                foreach ($errors as $error) {
                    $normalized = mb_strtolower((string) $error);
                    $isLieuError = str_contains($normalized, 'lieu');
                    if ($isLieuError && $form->has('lieu')) {
                        $form->get('lieu')->addError(new FormError($error));
                        continue;
                    }

                    $this->addFlash('error', $error);
                    $form->addError(new FormError($error));

                }

                return $this->render('evenement/new.html.twig', [

                    'form' => $form->createView(),

                    'is_patient' => $this->isGranted('ROLE_PATIENT'),

                ]);

            }



            $evenement->setCreeLe(new \DateTime());
            $evenement->setCreateur($user);
            $this->attachPlanningDecisionMetadata($evenement, $request);
            $em->persist($evenement);

            $em->flush();



            $this->addFlash('success', 'Operation effectuee avec succes.');

            

            if ($this->isGranted('ROLE_PATIENT')) {

                $this->addFlash('info', 'Votre evenement est en attente d\'approbation par un administrateur.');

            }



            if ($this->isGranted('ROLE_ADMIN')) {

                return $this->redirectToRoute('evenements_evenement_list');

            } else {

                return $this->redirectToRoute('evenements_client_events');

            }

        }



        return $this->render('evenement/new.html.twig', [

            'form' => $form->createView(),

            'is_patient' => $this->isGranted('ROLE_PATIENT'),

        ]);

    }



    #[Route('/{id}/modifier', name: 'evenement_update', methods: ['GET','POST'])]

    public function edit(Request $request, Evenement $evenement, EntityManagerInterface $em): Response

    {

        $user = $this->getUser();

        $isAdmin = $this->isGranted('ROLE_ADMIN');

        

        if (!$isAdmin) {

            if ($evenement->getCreateur() !== $user) {

                throw new AccessDeniedException('Acces refuse.');

            }

            

            if ($this->isGranted('ROLE_PATIENT') && $evenement->getStatut() === 'approuve') {

                $this->addFlash('warning', 'Operation non disponible dans cet etat.');

                if ($isAdmin) {

                    return $this->redirectToRoute('evenements_evenement_view', ['id' => $evenement->getId()]);

                } else {

                    return $this->redirectToRoute('evenements_client_event_view', ['id' => $evenement->getId()]);

                }

            }

        }



        $form = $this->createForm(EvenementType::class, $evenement, [

            'user_role' => ($user->getRoles()[0] ?? 'ROLE_USER'),

            'is_admin' => $isAdmin,

            'is_edit' => true,

            'series_candidates' => $this->buildSeriesCandidateChoices($evenement->getId()),

            'series_edition_number' => $this->extractEditionNumberFromTitle((string) $evenement->getTitre()),

        ]);

        

        $form->handleRequest($request);



        if ($form->isSubmitted() && $form->isValid()) {

            $errors = [];

            $this->applySurfaceEditionSelection($form, $evenement);

            

            if (!$evenement->getDateDebut()) {

                $errors[] = 'La date de debut est obligatoire.';

            }

            

            if (!$evenement->getDateFin()) {

                $errors[] = 'La date de fin est obligatoire.';

            }

            

            if ($evenement->getDateDebut() && $evenement->getDateFin()) {

                if ($evenement->getDateFin() < $evenement->getDateDebut()) {

                    $errors[] = 'La date de fin doit etre posterieure a la date de debut.';

                }

                

                $now = new \DateTime();

                $originalDateDebut = $evenement->getDateDebut(); // Note: vous devriez stocker l'ancienne date pour comparaison

                

                if ($evenement->getDateDebut() < $now) {

                    $errors[] = 'Vous ne pouvez pas mettre une date de debut dans le passe.';

                }

                

                $diff = $evenement->getDateDebut()->diff($evenement->getDateFin());

                if ($diff->days > 30) {

                    $errors[] = 'La duree de l\'evenement ne peut pas depasser 30 jours.';

                }

            }

            

            if ($evenement->getPlacesMax() !== null) {

                if ($evenement->getPlacesMax() <= 0) {

                    $errors[] = 'Le nombre de places doit etre superieur a zero.';

                }

                if ($evenement->getPlacesMax() > 10000) {

                    $errors[] = 'Le nombre de places ne peut pas depasser 10000.';

                }

                

                $inscriptionsCount = $em->getRepository(InscriptionEvenement::class)

                    ->count(['evenement' => $evenement]);

                if ($evenement->getPlacesMax() < $inscriptionsCount) {

                    $errors[] = 'Vous ne pouvez pas reduire le nombre de places en dessous du nombre d\'inscrits actuels (' . $inscriptionsCount . ').';

                }

            }

            

            if ($evenement->getTarif() !== null) {

                if ($evenement->getTarif() < 0) {

                    $errors[] = 'Le tarif ne peut pas etre negatif.';

                }

                if ($evenement->getTarif() > 10000) {

                    $errors[] = 'Le tarif ne peut pas depasser 10000 TND.';

                }

            }

            

            if (strlen($evenement->getTitre()) < 5) {

                $errors[] = 'Le titre doit contenir au moins 5 caracteres.';

            }

            

            if (strlen($evenement->getTitre()) > 200) {

                $errors[] = 'Le titre ne peut pas depasser 200 caracteres.';

            }

            

            if ($evenement->getDescription() && strlen($evenement->getDescription()) > 5000) {

                $errors[] = 'La description ne peut pas depasser 5000 caracteres.';

            }

            

            if ($evenement->getLieu() && strlen($evenement->getLieu()) > 500) {

                $errors[] = 'Le lieu ne peut pas depasser 500 caracteres.';

            }



            $this->appendSchedulingConflictErrors($evenement, $errors, $evenement->getId());

            $this->appendOperationalValidationErrors($evenement, $errors);

            

            if (!empty($errors)) {

                foreach ($errors as $error) {

                    $this->addFlash('error', $error);

                    $form->addError(new FormError($error));

                }

                return $this->render('evenement/edit.html.twig', [

                    'evenement' => $evenement,

                    'form' => $form->createView(),

                    'is_admin' => $isAdmin,

                ]);

            }



            $evenement->setModifieLe(new \DateTime());

            

            if ($isAdmin && $evenement->getStatut() === 'en_attente_approbation') {

                $evenement->setStatut('planifie');

                $this->addFlash('success', 'Operation effectuee avec succes.');

            } else {

                $this->addFlash('success', 'Operation effectuee avec succes.');

            }

            

            $em->flush();



