    #[Route('/{id}', name: 'evenement_view', methods: ['GET'])]

    public function view(Evenement $evenement, Request $request, EntityManagerInterface $em): Response

    {

        if (!$this->isGranted('ROLE_ADMIN')) {

            return $this->redirectToRoute('evenements_client_event_view', ['id' => $evenement->getId()]);

        }

        

        $user = $this->getUser();

        

        $nombreParticipants = $this->evenementRepository->getNombreParticipants($evenement);

        $tauxRemplissage = $this->evenementRepository->getTauxRemplissage($evenement);

        $revenusGeneres = $nombreParticipants * ($evenement->getTarif() ?? 0);

        

        $userInscription = null;

        if ($user) {

            try {

                $userInscription = $em->getRepository(InscriptionEvenement::class)

                    ->findOneBy(['evenement' => $evenement, 'utilisateur' => $user]);

            } catch (\Throwable $e) {

                $this->addFlash('warning', 'Operation non disponible dans cet etat.');

                $userInscription = null;

            }

        }



        $canSubscribe = $user ? $this->canUserSubscribe($user, $evenement, $em) : [

            'can_subscribe' => false,
            'message' => 'Connectez-vous pour vous inscrire.'

        ];



        $isAdmin = $this->isGranted('ROLE_ADMIN');

        $isCreator = $user && $evenement->getCreateur() && $evenement->getCreateur() === $user;



        $inscriptionsCount = $em->getRepository(InscriptionEvenement::class)->count(['evenement' => $evenement]);



        $canEdit = $isAdmin || $isCreator;

        $canDelete = ($isAdmin || $isCreator) && ($isAdmin || $inscriptionsCount == 0);

        $canInscribe = $user ? ($isAdmin ? true : ($canSubscribe['can_subscribe'] ?? false)) : false;



        $perms = [

            'can_edit' => (bool) $canEdit,

            'can_delete' => (bool) $canDelete,

            'can_inscribe' => (bool) $canInscribe,

        ];

        

        $participants = $em->getRepository(InscriptionEvenement::class)

            ->findBy(['evenement' => $evenement], ['dateInscription' => 'DESC']);



        return $this->render('evenement/view.html.twig', [

            'evenement' => $evenement,

            'nombreParticipants' => $nombreParticipants,

            'tauxRemplissage' => $tauxRemplissage,

            'revenusGeneres' => $revenusGeneres,

            'user_inscription' => $userInscription,

            'can_subscribe' => $canSubscribe,

            'perms' => $perms,

            'participants' => $participants,
            'display_description' => $this->buildEvenementDisplayDescription($evenement),

            'series_insights' => $this->evenementSeriesInsightsAIService->analyzeSeriesForEvent($evenement),

            'experience_pack' => $this->evenementExperienceDesignService->buildExperiencePack($evenement),

        ]);

    }



    #[Route('/api/recommandations-lieux', name: 'api_lieux_recommandes', methods: ['GET'])]
    public function apiLieuxRecommandes(Request $request): JsonResponse
    {
        $ville = trim((string) $request->query->get('ville', ''));
        $type = trim((string) $request->query->get('type', ''));
        $mode = trim((string) $request->query->get('mode', ''));

        if ($type === '') {
            $type = 'formation';
        }
        if ($mode === '') {
            $mode = 'presentiel';
        }

        $capacity = $request->query->getInt('capacity', 0);
        if ($capacity <= 0) {
            $capacity = $request->query->getInt('capacite', 0);
        }

        $title = trim((string) $request->query->get('title', ''));
        $description = trim((string) $request->query->get('description', ''));
        $budget = $request->query->get('budget');
        $durationHours = $request->query->get('duration_hours');

        if ($ville === '') {
            return $this->json([
                'success' => false,
                'message' => 'Veuillez renseigner une ville pour rechercher un lieu.',
                'lieux' => [],
            ], 400);
        }

        $context = [
            'mode' => $mode,
            'title' => $title,
            'description' => $description,
            'budget' => $budget,
            'duration_hours' => $durationHours,
        ];

        $result = $this->evenementVenueRecommendationService->recommend(
            $ville,
            $type,
            $capacity > 0 ? $capacity : null,
            $context
        );

        return $this->json($result);
    }

    #[Route('/api/validation-lieu', name: 'api_validation_lieu', methods: ['GET'])]
    public function apiValidationLieu(Request $request): JsonResponse
    {
        $lieu = trim((string) $request->query->get('lieu', ''));
        $mode = trim((string) $request->query->get('mode', 'presentiel'));
        if ($lieu === '') {
            return $this->json([
                'success' => false,
                'valid' => false,
                'message' => 'Saisissez un lieu pour lancer la verification.',
            ], 400);
        }

        $evenement = new Evenement();
        $evenement->setLieu($lieu);
        $evenement->setMode($mode !== '' ? $mode : 'presentiel');

        $insights = $this->operationalInsightsService->analyze($evenement, [
            'venue_source' => 'manual',
        ]);

        if (($insights['location_valid'] ?? true) === false) {
            return $this->json([
                'success' => true,
                'valid' => false,
                'message' => (string) ($insights['location_message'] ?? 'Lieu non valide.'),
            ]);
        }

        return $this->json([
            'success' => true,
            'valid' => true,
            'message' => 'Lieu verifie. Vous pouvez continuer.',
        ]);
    }

    #[Route('/api/plan-ressources', name: 'api_plan_ressources', methods: ['GET'])]

    public function apiPlanRessources(Request $request): JsonResponse

    {

        $type = trim((string) $request->query->get('type', ''));

        $mode = trim((string) $request->query->get('mode', ''));

        $capacity = $request->query->getInt('capacity', 0);



        if ($type === '' || $mode === '' || $capacity <= 0) {

            return $this->json([

                'success' => false,

                'message' => 'Renseignez type, mode et capacite pour calculer le plan de ressources.',

            ], 400);

        }



        $plan = $this->evenementResourcePlanningService->buildPlan($type, $mode, $capacity);



        return $this->json([

            'success' => true,

            'plan' => $plan,

        ]);

    }




    #[Route('/api/planning-ia', name: 'api_planning_ia', methods: ['GET'])]
    public function apiPlanningIa(Request $request): JsonResponse
    {
        $type = trim((string) $request->query->get('type', ''));
        $mode = trim((string) $request->query->get('mode', ''));
        $audience = trim((string) $request->query->get('audience', 'mixte'));
        $level = trim((string) $request->query->get('level', 'intermediaire'));
        $duration = max(60, min(720, $request->query->getInt('duration', 180)));

        if ($type === '') {
            $type = 'formation';
        }
        if ($mode === '') {
            $mode = 'presentiel';
        }

        $result = $this->evenementPlanningModelService->predict([
            'event_type' => $type,
            'mode' => $mode,
            'audience' => $audience !== '' ? $audience : 'mixte',
            'level' => $level !== '' ? $level : 'intermediaire',
            'duration_total_min' => $duration,
        ]);

        if (!($result['ready'] ?? false)) {
            return $this->json([
                'success' => false,
                'ready' => false,
                'message' => (string) ($result['message'] ?? 'Service IA indisponible.'),
            ], 200);
        }

        return $this->json([
            'success' => true,
            'ready' => true,
            'recommendation' => $result['recommendation'],
        ]);
    }
    #[Route('/{id}/client-view', name: 'client_event_view', methods: ['GET'])]

    public function clientEventView(Evenement $evenement, Request $request, EntityManagerInterface $em): Response

