    private function appendSchedulingConflictErrors(Evenement $evenement, array &$errors, ?int $excludeEventId): void

    {

        $conflicts = $this->evenementRepository->findSchedulingConflicts($evenement, $excludeEventId);

        if (count($conflicts) === 0) {

            return;

        }



        $firstConflict = $conflicts[0];

        $errors[] = sprintf(

            'Conflit de planification : cet evenement chevauche "%s" (%s - %s) au meme lieu. Merci de choisir un autre horaire ou un autre lieu.',

            (string) $firstConflict->getTitre(),

            $firstConflict->getDateDebut()->format('d/m/Y H:i'),

            $firstConflict->getDateFin()->format('d/m/Y H:i')

        );

    }



    private function appendOperationalValidationErrors(Evenement $evenement, array &$errors, ?string $venueSource = null): void

    {

        $insights = $this->operationalInsightsService->analyze($evenement, [
            'venue_source' => $venueSource,
        ]);



        if (($insights['location_valid'] ?? true) === false && !empty($insights['location_message'])) {

            $errors[] = (string) $insights['location_message'];

        }

    }



    private function validateEvenement(Evenement $evenement, ?string $venueSource = null): array

    {

        $errors = [];



        if (!$evenement->getDateDebut()) {

            $errors[] = 'La date de debut est obligatoire.';

        }



        if (!$evenement->getDateFin()) {

            $errors[] = 'La date de fin est obligatoire.';

        }



        if ($evenement->getDateDebut() && $evenement->getDateFin()) {

            if ($evenement->getDateFin() < $evenement->getDateDebut()) {

                $errors[] = 'La date de fin doit etre posterieure a la date de debut.';

            }



            $minDate = new \DateTime();

            $minDate->modify('+2 days');



            if ($evenement->getDateDebut() < $minDate) {

                $errors[] = 'La date doit etre au moins 48h a l\'avance.';

            }



            $diff = $evenement->getDateDebut()->diff($evenement->getDateFin());



            if ($diff->days > 30) {

                $errors[] = 'Duree max : 30 jours.';

            }

        }



        if ($evenement->getPlacesMax() !== null) {

            if ($evenement->getPlacesMax() <= 0) {

                $errors[] = 'Places > 0 obligatoire.';

            }



            if ($evenement->getPlacesMax() > 10000) {

                $errors[] = 'Places max : 10000.';

            }

        }



        $this->appendSchedulingConflictErrors($evenement, $errors, $evenement->getId());

        $this->appendOperationalValidationErrors($evenement, $errors, $venueSource);



        return $errors;

    }



